source:
Level -> {
  -> Debug:
  -> Info:
  -> Warn:
  -> Error:
}

LogEvent -> {
  Level:level
  String:message
}

format -> {
  LogEvent:e
  -> e.level ? {
    Debug: -> "[DBG] " + e.message
    Info: -> "[INF] " + e.message
    Warn: -> "[WRN] " + e.message
    Error: -> "[ERR] " + e.message
  }
}

consoleLogger -> {
  LogEvent -< e {
    -> io.print{message -> format{e -> e}!}!
  }
  log -> {
    LogEvent:msg
    >- LogEvent{level -> msg.level message -> msg.message}
  }
}
